-- ============================================================================
-- Quiz Seed: 2 Samuel — Part 1 (Chapters 1–10)
-- 3 difficulties × 10 chapters = 160 total questions
-- kids: 3 Qs, teens: 5 Qs, adults: 8 Qs per chapter
-- correct_answer is always 'a'
-- ============================================================================

-- ═══ 2 Samuel Chapter 1 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Samuel', 1, 'kids', 1, 'What news did the Amalekite bring to David?', 'Saul and Jonathan were dead', 'The Philistines had fled', 'Jonathan had become king', 'Abner had won the battle', 'a', '2 Samuel 1:4 — "The people are fled from the battle, and many of the people also are fallen and dead; and Saul and Jonathan his son are dead also."'),
('2 Samuel', 1, 'kids', 2, 'What did David and his men do when they heard Saul and Jonathan had died?', 'They celebrated', 'They mourned and wept', 'They went to battle', 'They fled to the desert', 'a', '2 Samuel 1:11-12 — "Then David took hold on his clothes, and rent them; and likewise all the men that were with him: And they mourned, and wept."'),
('2 Samuel', 1, 'kids', 3, 'What famous words did David say about Saul and Jonathan in his song?', 'How are the mighty fallen', 'Blessed are the peacemakers', 'The Lord is my shepherd', 'Fear not, for I am with you', 'a', '2 Samuel 1:19 — "The beauty of Israel is slain upon thy high places: how are the mighty fallen!"'),
-- Teens
('2 Samuel', 1, 'teens', 1, 'Where did David return from when he heard the news of the battle?', 'From Hebron', 'From the slaughter of the Amalekites', 'From the wilderness of Judah', 'From the city of Gath', 'a', '2 Samuel 1:1 — "David was returned from the slaughter of the Amalekites."'),
('2 Samuel', 1, 'teens', 2, 'What did the Amalekite claim he had done to end Saul''s suffering?', 'He killed him at Saul''s own request', 'He carried him off the battlefield', 'He gave him water to drink', 'He hid him from the Philistines', 'a', '2 Samuel 1:9-10 — Saul said, "Stand upon me, and slay me," and the Amalekite said, "I stood upon him, and slew him."'),
('2 Samuel', 1, 'teens', 3, 'What items from Saul did the Amalekite bring to David as proof?', 'The crown and bracelet', 'The sword and shield', 'The robe and sandals', 'The ring and scepter', 'a', '2 Samuel 1:10 — "I took the crown that was upon his head, and the bracelet that was on his arm, and have brought them hither unto my lord."'),
('2 Samuel', 1, 'teens', 4, 'Why did David have the Amalekite killed?', 'Because he was an enemy soldier', 'Because he claimed to have killed the LORD''s anointed', 'Because he had stolen Saul''s crown', 'Because he lied to David', 'a', '2 Samuel 1:16 — "Thy blood be upon thy head; for thy mouth hath testified against thee, saying, I have slain the LORD''s anointed."'),
('2 Samuel', 1, 'teens', 5, 'In David''s lament, which city did he tell not to publish the news of Israel''s defeat?', 'Gath and Ashkelon', 'Jerusalem and Hebron', 'Bethlehem and Beersheba', 'Ramah and Gibeah', 'a', '2 Samuel 1:20 — "Tell it not in Gath, publish it not in the streets of Askelon; lest the daughters of the Philistines rejoice."'),
-- Adults
('2 Samuel', 1, 'adults', 1, 'How many days after the battle of Jezreel did the Amalekite messenger arrive at Ziklag?', 'On the third day', 'On the second day', 'On the first day', 'On the seventh day', 'a', '2 Samuel 1:2 — "It came even to pass on the third day, that, behold, a man came out of the camp from Saul with his clothes rent, and earth upon his head."'),
('2 Samuel', 1, 'adults', 2, 'What did David call his lament over Saul and Jonathan, and where was it written?', 'The Song of the Bow, written in the book of Jasher', 'The Song of Sorrow, written in the book of Samuel', 'The Lamentation of Israel, written on a stone', 'The Elegy of Zion, written in the royal archives', 'a', '2 Samuel 1:18 — "He bade them teach the children of Judah the use of the bow: behold, it is written in the book of Jasher."'),
('2 Samuel', 1, 'adults', 3, 'How does David describe the love of Jonathan for him in the lament?', 'Passing the love of women', 'Stronger than the love of a father', 'Greater than the love of a brother', 'More faithful than the love of a friend', 'a', '2 Samuel 1:26 — "Thy love to me was wonderful, passing the love of women."'),
('2 Samuel', 1, 'adults', 4, 'What metaphor does David use in his lament to describe Saul and Jonathan''s swiftness?', 'Swifter than eagles, stronger than lions', 'Like arrows from the bow', 'Like the wind on the mountains', 'Faster than horses in battle', 'a', '2 Samuel 1:23 — "They were swifter than eagles, they were stronger than lions."'),
('2 Samuel', 1, 'adults', 5, 'What instruction did David give regarding the mountains of Gilboa in his lament?', 'Let there be no dew nor rain upon them', 'Let no enemy ever tread upon them', 'Let Israel plant vineyards there', 'Let the high places be torn down', 'a', '2 Samuel 1:21 — "Ye mountains of Gilboa, let there be no dew, neither let there be rain, upon you, nor fields of offerings."'),
('2 Samuel', 1, 'adults', 6, 'How does David''s lament describe the daughters of Israel''s relationship with Saul?', 'He clothed them with scarlet and ornaments of gold', 'He gave them fields and vineyards', 'He protected them from their enemies', 'He taught them the ways of the LORD', 'a', '2 Samuel 1:24 — "Ye daughters of Israel, weep over Saul, who clothed you in scarlet, with other delights, who put on ornaments of gold upon your apparel."'),
('2 Samuel', 1, 'adults', 7, 'What does David call the Philistines and their land in his lament?', 'The uncircumcised and the land of the enemy', 'The pagans and the land of darkness', 'The oppressors and the land of idols', 'The wicked and the cursed land', 'a', '2 Samuel 1:20 — David says "the daughters of the Philistines" and refers to the Philistines as "the uncircumcised" (2 Samuel 1:20).'),
('2 Samuel', 1, 'adults', 8, 'What theological significance lies in David''s execution of the Amalekite despite his grief for Saul?', 'David upheld the sacred principle that the LORD''s anointed must not be struck down, even in mercy', 'David wanted to show strength before the army', 'David was following the Mosaic law on murder', 'David feared the Philistines would hear of Saul''s dishonor', 'a', '2 Samuel 1:14 — "How wast thou not afraid to stretch forth thine hand to destroy the LORD''s anointed?" — David''s reverence for divine anointing superseded personal feelings.');

-- ═══ 2 Samuel Chapter 2 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Samuel', 2, 'kids', 1, 'Over which tribe did David become king first?', 'Judah', 'Benjamin', 'Levi', 'Ephraim', 'a', '2 Samuel 2:4 — "The men of Judah came, and there they anointed David king over the house of Judah."'),
('2 Samuel', 2, 'kids', 2, 'Who was made king over Israel while David ruled Judah?', 'Ish-bosheth', 'Abner', 'Joab', 'Asahel', 'a', '2 Samuel 2:10 — "Ish-bosheth Saul''s son was forty years old when he began to reign over Israel."'),
('2 Samuel', 2, 'kids', 3, 'What city did David make his capital when he became king of Judah?', 'Hebron', 'Jerusalem', 'Bethlehem', 'Jericho', 'a', '2 Samuel 2:11 — "David was king in Hebron over the house of Judah seven years and six months."'),
-- Teens
('2 Samuel', 2, 'teens', 1, 'What did David do before going up to Hebron to become king?', 'He inquired of the LORD', 'He consulted Joab his commander', 'He gathered his army', 'He sent messengers to all of Israel', 'a', '2 Samuel 2:1 — "David inquired of the LORD, saying, Shall I go up into any of the cities of Judah? And the LORD said unto him, Go up."'),
('2 Samuel', 2, 'teens', 2, 'Who was the commander of Ish-bosheth''s army?', 'Abner the son of Ner', 'Joab the son of Zeruiah', 'Asahel the brother of Joab', 'Rechab the son of Rimmon', 'a', '2 Samuel 2:8 — "Abner the son of Ner, captain of Saul''s host, took Ish-bosheth the son of Saul."'),
('2 Samuel', 2, 'teens', 3, 'What was the name of the place where the two sides met and held a contest of young men?', 'The pool of Gibeon', 'The valley of Elah', 'The field of Rephaim', 'The hill of Moreh', 'a', '2 Samuel 2:13 — "They met together by the pool of Gibeon: and they sat down, the one on the one side of the pool, and the other on the other side."'),
('2 Samuel', 2, 'teens', 4, 'How many young men died in the contest at Gibeon that started the battle?', 'Twelve from each side, twenty-four total', 'Seven from each side, fourteen total', 'Three from each side, six total', 'Ten from each side, twenty total', 'a', '2 Samuel 2:15-16 — Twelve from Benjamin for Ish-bosheth and twelve of the servants of David met, and they all fell together, so "that place was called Helkath-hazzurim."'),
('2 Samuel', 2, 'teens', 5, 'Who was Asahel, and what made him notable in battle?', 'He was Joab''s brother and was as light of foot as a wild roe', 'He was Abner''s son and the fastest horseman in Israel', 'He was David''s nephew and the strongest warrior', 'He was a Benjaminite and the captain of fifty men', 'a', '2 Samuel 2:18 — "And Asahel was as light of foot as a wild roe."'),
-- Adults
('2 Samuel', 2, 'adults', 1, 'What kind words did David send to the men of Jabesh-gilead and why?', 'He blessed them for burying Saul, and promised them kindness', 'He warned them to submit to his kingship or face war', 'He invited them to join his army at Hebron', 'He rebuked them for not fighting to protect Saul', 'a', '2 Samuel 2:5-6 — "Blessed be ye of the LORD, that ye have shewed this kindness unto your lord, even unto Saul, and have buried him...I also will requite you this kindness."'),
('2 Samuel', 2, 'adults', 2, 'Over what territory did Abner make Ish-bosheth king?', 'Gilead, Ashurites, Jezreel, Ephraim, Benjamin, and all Israel', 'Only the tribe of Benjamin and Manasseh', 'The northern tribes of Dan and Naphtali', 'All of Canaan except Judah and Simeon', 'a', '2 Samuel 2:9 — "He made him king over Gilead, and over the Ashurites, and over Jezreel, and over Ephraim, and over Benjamin, and over all Israel."'),
('2 Samuel', 2, 'adults', 3, 'What was the name given to the site of the twelve-against-twelve contest at Gibeon?', 'Helkath-hazzurim', 'Baal-perazim', 'Ramath-lehi', 'En-hakkore', 'a', '2 Samuel 2:16 — "Wherefore that place was called Helkath-hazzurim, which is in Gibeon."'),
('2 Samuel', 2, 'adults', 4, 'Why did Abner warn Asahel to stop chasing him?', 'Because he did not want to kill Joab''s brother and cause a blood feud', 'Because Asahel was too young to fight', 'Because a truce had been declared', 'Because Abner feared being killed by Asahel', 'a', '2 Samuel 2:22 — "Turn thee aside from following me: wherefore should I smite thee to the ground? how then should I hold up my face to Joab thy brother?"'),
('2 Samuel', 2, 'adults', 5, 'With what part of his spear did Abner kill Asahel?', 'The hinder end of the spear', 'The iron tip of the spear', 'The shaft of the spear', 'The butt end wrapped in bronze', 'a', '2 Samuel 2:23 — "Abner with the hinder end of the spear smote him under the fifth rib, that the spear came out behind him; and he fell down there, and died in the same place."'),
('2 Samuel', 2, 'adults', 6, 'How did the two armies finally stop fighting after the battle at Gibeon?', 'Abner called for a truce and Joab agreed at Joab''s request', 'The sun went down and they agreed to stop at Abner''s appeal', 'The Philistines attacked and they had to unite', 'A messenger from David commanded them to cease', 'a', '2 Samuel 2:26-28 — Abner called out to Joab, "Shall the sword devour for ever?" and Joab blew a trumpet and the people stood still.'),
('2 Samuel', 2, 'adults', 7, 'What were the respective casualty figures for Joab''s men and Abner''s men in the battle?', 'Joab lost 19 men plus Asahel; Abner lost 360 Benjaminites', 'Joab lost 40 men; Abner lost 200 men', 'Joab lost 12 men; Abner lost 12 men', 'Joab lost 100 men; Abner lost 500 men', 'a', '2 Samuel 2:30-31 — "Of David''s servants there lacked nineteen men and Asahel...David''s servants had smitten of Benjamin, and of Abner''s men, so that three hundred and threescore men died."'),
('2 Samuel', 2, 'adults', 8, 'What theological principle is illustrated by David asking God before moving to Hebron?', 'That leaders must seek divine guidance before every major decision', 'That God only speaks to kings through prophets', 'That the tribe of Judah was superior to the others', 'That military success depends on numbers', 'a', '2 Samuel 2:1 — David "inquired of the LORD" before acting, illustrating the principle that godly leadership begins with prayer and divine consultation.');

-- ═══ 2 Samuel Chapter 3 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Samuel', 3, 'kids', 1, 'What did Abner decide to do after fighting against David for a long time?', 'He decided to help make David king over all Israel', 'He decided to run away to Egypt', 'He decided to fight harder for Ish-bosheth', 'He decided to retire from the army', 'a', '2 Samuel 3:21 — Abner said to David, "I will arise and go, and will gather all Israel unto my lord the king, that they may make a league with thee."'),
('2 Samuel', 3, 'kids', 2, 'Who killed Abner?', 'Joab', 'David', 'Ish-bosheth', 'Asahel', 'a', '2 Samuel 3:27 — "Joab took him aside in the gate to speak with him quietly, and smote him there under the fifth rib, that he died."'),
('2 Samuel', 3, 'kids', 3, 'How did David show he was sad when Abner died?', 'He fasted all day and wept at the funeral', 'He tore his robe and sat in the dust', 'He stopped being king for seven days', 'He sent all his servants away', 'a', '2 Samuel 3:35 — "David fasted until even. And all the people came to comfort David...David sware, saying...I taste bread, or ought else, till the sun be down."'),
-- Teens
('2 Samuel', 3, 'teens', 1, 'Why did Abner become angry with Ish-bosheth and decide to switch sides?', 'Because Ish-bosheth accused him of sleeping with Saul''s concubine Rizpah', 'Because Ish-bosheth refused to pay his soldiers', 'Because Ish-bosheth made peace with David without telling him', 'Because Ish-bosheth demoted him from command', 'a', '2 Samuel 3:7-8 — Ish-bosheth said, "Wherefore hast thou gone in unto my father''s concubine?" And Abner was very wroth.'),
('2 Samuel', 3, 'teens', 2, 'What did David require before he would meet with Abner?', 'That Michal, Saul''s daughter, be returned to him', 'That Abner bring one hundred Philistine heads', 'That Abner come alone without any soldiers', 'That Abner swear an oath before the elders of Israel', 'a', '2 Samuel 3:13 — "David said, Well; I will make a league with thee: but one thing I require of thee, that is, Thou shalt not see my face, except thou first bring Michal Saul''s daughter."'),
('2 Samuel', 3, 'teens', 3, 'Why did Joab hate Abner and want to kill him?', 'Because Abner had killed his brother Asahel in battle', 'Because Abner had stolen his position as army commander', 'Because Abner had insulted David publicly', 'Because Abner had betrayed Joab''s family', 'a', '2 Samuel 3:30 — "Joab and Abishai his brother slew Abner, because he had slain their brother Asahel at Gibeon in the battle."'),
('2 Samuel', 3, 'teens', 4, 'How many sons did David have born to him in Hebron, and who was the firstborn?', 'Six sons; the firstborn was Amnon by Ahinoam', 'Three sons; the firstborn was Absalom', 'Four sons; the firstborn was Chileab', 'Five sons; the firstborn was Adonijah', 'a', '2 Samuel 3:2 — "Unto David were sons born in Hebron: and his firstborn was Amnon, of Ahinoam the Jezreelitess."'),
('2 Samuel', 3, 'teens', 5, 'What curse did David pronounce on Joab''s house for killing Abner?', 'Let there not fail from the house of Joab one that hath an issue or a leper', 'Let the sword never depart from Joab''s household', 'Let Joab''s descendants never see peace', 'Let Joab''s name be blotted out of Israel', 'a', '2 Samuel 3:29 — "Let it rest on the head of Joab, and on all his father''s house; and let there not fail from the house of Joab one that hath an issue, or that is a leper, or that leaneth on a staff, or that falleth on the sword, or that lacketh bread."'),
-- Adults
('2 Samuel', 3, 'adults', 1, 'What does the opening verse of chapter 3 reveal about the political situation between the two houses?', 'There was a long war; the house of David waxed stronger and stronger while the house of Saul waxed weaker and weaker', 'The two houses had made a treaty that was slowly breaking down', 'The house of Saul was growing in strength through Abner''s victories', 'Israel had divided evenly between the two kings', 'a', '2 Samuel 3:1 — "Now there was long war between the house of Saul and the house of David: but David waxed stronger and stronger, and the house of Saul waxed weaker and weaker."'),
('2 Samuel', 3, 'adults', 2, 'What was the name of Abner''s father, making him a member of Saul''s own clan?', 'Ner, from the tribe of Benjamin', 'Jesse, from the tribe of Judah', 'Shimei, from the tribe of Levi', 'Kish, from the house of Saul', 'a', '2 Samuel 3:6 — "Abner the son of Ner" — Ner was Saul''s uncle, making Abner Saul''s cousin and a powerful figure within the Benjaminite clan.'),
('2 Samuel', 3, 'adults', 3, 'What specific promise did Abner make to David regarding his mission to unite Israel?', 'To go throughout all Israel and cause Israel to make a league with David and reign over all that his heart desired', 'To present David to the elders within three days', 'To bring the crown of Ish-bosheth to David personally', 'To ensure all the northern tribes swore allegiance by the new moon', 'a', '2 Samuel 3:21 — Abner said he would "gather all Israel unto my lord the king, that they may make a league with thee, and that thou mayest reign over all that thine heart desireth."'),
('2 Samuel', 3, 'adults', 4, 'What does the text say David sent with Abner to indicate the meeting was peaceful?', 'Abner departed in peace', 'David gave Abner silver and gold', 'David sent a feast and provisions', 'David gave Abner a letter for the elders', 'a', '2 Samuel 3:21 — "David sent Abner away; and he went in peace."'),
('2 Samuel', 3, 'adults', 5, 'What did David say to demonstrate publicly he was innocent of Abner''s murder?', 'That the blood was on Joab and his father''s house and that David was guiltless before the LORD', 'That he would punish Joab with fifty lashes', 'That he would hand Joab over to the elders of Israel for judgment', 'That he had tried to warn Abner of Joab''s intentions', 'a', '2 Samuel 3:28 — "I and my kingdom are guiltless before the LORD for ever from the blood of Abner the son of Ner."'),
('2 Samuel', 3, 'adults', 6, 'What was the people''s response to David''s fasting and mourning over Abner?', 'It pleased all the people and all Israel understood that it was not of the king to slay Abner', 'The people mourned with David for seven days', 'The people were frightened and thought David would punish Joab', 'The elders urged David to put Joab to death immediately', 'a', '2 Samuel 3:36-37 — "All the people took notice of it, and it pleased them...For all the people and all Israel understood that day that it was not of the king to slay Abner the son of Ner."'),
('2 Samuel', 3, 'adults', 7, 'Who was Michal''s husband from whom she was taken to be returned to David?', 'Phaltiel the son of Laish', 'Adriel the son of Barzillai', 'Palti the son of Raphu', 'Uzziah the son of Abinadab', 'a', '2 Samuel 3:15 — "Ish-bosheth sent, and took her from her husband, even from Phaltiel the son of Laish."'),
('2 Samuel', 3, 'adults', 8, 'What does Phaltiel''s response to losing Michal reveal about the human cost of David''s political dealings?', 'He wept and followed her to Bahurim, showing deep personal grief over David''s political claim', 'He was glad to be free of her and went home rejoicing', 'He petitioned Ish-bosheth for compensation', 'He joined Abner''s army in protest', 'a', '2 Samuel 3:16 — "Her husband went with her along weeping behind her to Bahurim. Then said Abner unto him, Go, return. And he returned." This poignant detail shows the human grief behind dynastic politics.');

-- ═══ 2 Samuel Chapter 4 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Samuel', 4, 'kids', 1, 'What did Rechab and Baanah do to Ish-bosheth?', 'They murdered him while he was sleeping', 'They captured him and brought him to David', 'They put him in prison', 'They sent him away to a foreign land', 'a', '2 Samuel 4:7 — "They smote him, and slew him, and beheaded him, and took his head, and gat them away through the plain all night."'),
('2 Samuel', 4, 'kids', 2, 'What did Rechab and Baanah bring to David after killing Ish-bosheth?', 'The head of Ish-bosheth', 'Ish-bosheth''s crown and weapons', 'A letter from the elders of Israel', 'The keys to Ish-bosheth''s palace', 'a', '2 Samuel 4:8 — "They brought the head of Ish-bosheth unto David to Hebron."'),
('2 Samuel', 4, 'kids', 3, 'What did David do to Rechab and Baanah for killing Ish-bosheth?', 'He had them killed and their hands and feet cut off', 'He rewarded them with silver and gold', 'He made them commanders in his army', 'He sent them away from his kingdom', 'a', '2 Samuel 4:12 — "David commanded his young men, and they slew them, and cut off their hands and their feet, and hanged them up over the pool in Hebron."'),
-- Teens
('2 Samuel', 4, 'teens', 1, 'What happened to Ish-bosheth''s courage when he heard Abner was dead?', 'His hands were feeble and all Israel was troubled', 'He strengthened himself and prepared for war', 'He fled to Gilead for safety', 'He made a treaty with David immediately', 'a', '2 Samuel 4:1 — "When Saul''s son heard that Abner was dead in Hebron, his hands were feeble, and all the Israelites were troubled."'),
('2 Samuel', 4, 'teens', 2, 'Who were Rechab and Baanah, and where were they from?', 'They were captains of bands and sons of Rimmon the Beerothite, Benjaminites', 'They were Philistine mercenaries hired by David''s enemies', 'They were sons of Abner who wanted to avenge their father', 'They were servants from Ish-bosheth''s household in Mahanaim', 'a', '2 Samuel 4:2 — "Saul''s son had two men that were captains of bands: the name of the one was Baanah, and the name of the other Rechab, the sons of Rimmon a Beerothite, of the children of Benjamin."'),
('2 Samuel', 4, 'teens', 3, 'What was Ish-bosheth doing when Rechab and Baanah entered the house to kill him?', 'He was sleeping on his bed at noon', 'He was eating his midday meal', 'He was meeting with his advisors', 'He was reading the law in his chamber', 'a', '2 Samuel 4:5 — "Rechab and Baanah...came about the heat of the day to the house of Ish-bosheth, who lay on a bed at noon."'),
('2 Samuel', 4, 'teens', 4, 'How did David respond to Rechab and Baanah''s claim that God had avenged him through their deed?', 'He rejected their reasoning and condemned them for murdering a righteous man in his bed', 'He praised them and gave them gold', 'He was uncertain and consulted the priests', 'He accepted their claim but sent them away without reward', 'a', '2 Samuel 4:11 — "How much more, when wicked men have slain a righteous person in his own house upon his bed? shall I not therefore now require his blood of your hand?"'),
('2 Samuel', 4, 'teens', 5, 'Who was Mephibosheth, and why is he mentioned in chapter 4?', 'He was Jonathan''s son who was lame in both feet, mentioned as the remaining heir of Saul''s house', 'He was Ish-bosheth''s son who fled to Mahanaim', 'He was Abner''s nephew who survived the purge', 'He was a Benjaminite soldier who escaped Rechab and Baanah', 'a', '2 Samuel 4:4 — "Jonathan, Saul''s son, had a son that was lame of his feet...and his name was Mephibosheth."'),
-- Adults
('2 Samuel', 4, 'adults', 1, 'What city did the Beerothites flee to, and where does the text say Beeroth was originally located?', 'They fled to Gittaim and sojourned there; Beeroth was reckoned to Benjamin', 'They fled to Hebron and joined David''s army; Beeroth was in Judah', 'They fled to Gath and became Philistine servants; Beeroth was in Ephraim', 'They fled to Mahanaim; Beeroth was in Gilead', 'a', '2 Samuel 4:3 — "The Beerothites fled to Gittaim, and were sojourners there until this day."'),
('2 Samuel', 4, 'adults', 2, 'Under what false pretense did Rechab and Baanah enter the house of Ish-bosheth?', 'As if they would have fetched wheat', 'As messengers bearing urgent news', 'As physicians attending to the king', 'As guards relieving the night watch', 'a', '2 Samuel 4:6 — "They came thither into the midst of the house, as though they would have fetched wheat."'),
('2 Samuel', 4, 'adults', 3, 'What did David do with the head of Ish-bosheth?', 'He buried it in the sepulchre of Abner in Hebron', 'He sent it back to Mahanaim as a warning', 'He placed it at the gate of the city as a sign', 'He gave it to the elders of Benjamin for burial', 'a', '2 Samuel 4:12 — "They took the head of Ish-bosheth, and buried it in the sepulchre of Abner in Hebron."'),
('2 Samuel', 4, 'adults', 4, 'How does David''s reference to the Amalekite in chapter 4 connect to the events of chapter 1?', 'He cites the Amalekite''s execution as precedent for punishing those who kill God''s anointed', 'He uses the Amalekite''s story to comfort Rechab and Baanah', 'He reminds them that the Amalekite was rewarded before being punished', 'He questions whether the Amalekite''s example was just', 'a', '2 Samuel 4:10 — "When one told me, saying, Behold, Saul is dead, thinking to have brought good tidings, I took hold of him, and slew him in Ziklag, who thought that I would have given him a reward for his tidings."'),
('2 Samuel', 4, 'adults', 5, 'What was Ish-bosheth''s age and length of reign over Israel?', 'He was forty years old and reigned two years', 'He was thirty years old and reigned seven years', 'He was twenty-five years old and reigned five years', 'He was fifty years old and reigned three years', 'a', '2 Samuel 2:10 — "Ish-bosheth Saul''s son was forty years old when he began to reign over Israel, and reigned two years."'),
('2 Samuel', 4, 'adults', 6, 'What does David''s consistent refusal to profit from the deaths of Saul''s house reveal about his character?', 'His rise to unified kingship was achieved through justice and respect for God''s anointed, not treachery', 'He was militarily too weak to punish Joab or reward assassins', 'He was bound by a secret oath to Saul''s family', 'He was afraid of the northern tribes'' reaction', 'a', '2 Samuel 4:9 — "David answered Rechab and Baanah his brother...As the LORD liveth, who hath redeemed my soul out of all adversity." David''s consistent principled stance established his moral legitimacy.'),
('2 Samuel', 4, 'adults', 7, 'How does the phrase "righteous person" applied to Ish-bosheth in David''s response reflect on Ish-bosheth''s character?', 'It acknowledges that Ish-bosheth, though a political opponent, was an innocent man wrongfully murdered', 'It means Ish-bosheth had kept the Mosaic law perfectly', 'It is a royal title used for all Israelite kings', 'It suggests Ish-bosheth had repented of opposing David', 'a', '2 Samuel 4:11 — David called Ish-bosheth "a righteous person," indicating his innocence of any crime that warranted execution — he was simply a pawn of political circumstance.'),
('2 Samuel', 4, 'adults', 8, 'What does the notice about Mephibosheth in verse 4 (interrupting the narrative) foreshadow?', 'It prepares the reader for David''s later act of covenant loyalty to Jonathan''s surviving heir in chapter 9', 'It explains why Benjamin was loyal to Ish-bosheth', 'It shows that the line of Saul was completely wiped out', 'It demonstrates that David had already found Jonathan''s heirs', 'a', '2 Samuel 4:4 — The editorial note about Mephibosheth here sets up the covenant-faithfulness narrative of chapter 9, where David fulfills his promises to Jonathan.');

-- ═══ 2 Samuel Chapter 5 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Samuel', 5, 'kids', 1, 'Over how much of Israel did David become king after Ish-bosheth died?', 'All Israel', 'Only Judah and Benjamin', 'Only the northern tribes', 'Half of Israel', 'a', '2 Samuel 5:3 — "All the elders of Israel came to the king to Hebron...and they anointed David king over Israel."'),
('2 Samuel', 5, 'kids', 2, 'What city did David capture to make his new capital?', 'Jerusalem', 'Hebron', 'Jericho', 'Bethlehem', 'a', '2 Samuel 5:7 — "David took the strong hold of Zion: the same is the city of David."'),
('2 Samuel', 5, 'kids', 3, 'Who helped David build his palace in Jerusalem?', 'Hiram king of Tyre', 'Solomon his son', 'Joab his general', 'The elders of Judah', 'a', '2 Samuel 5:11 — "Hiram king of Tyre sent messengers to David, and cedar trees, and carpenters, and masons: and they built David an house."'),
-- Teens
('2 Samuel', 5, 'teens', 1, 'What three reasons did the tribes of Israel give for wanting David to be their king?', 'He was their bone and flesh, he had led Israel before, and the LORD had promised him', 'He was the most powerful warrior, he was of royal blood, and he was wise', 'He was humble, he was just, and he was already king of Judah', 'Samuel had anointed him, he had defeated Goliath, and Saul had chosen him', 'a', '2 Samuel 5:1-2 — "We are thy bone and thy flesh. Also in time past, when Saul was king over us, thou wast he that leddest out and broughtest in Israel: and the LORD said to thee, Thou shalt feed my people Israel."'),
('2 Samuel', 5, 'teens', 2, 'How old was David when he became king and how long did he reign altogether?', 'Thirty years old; he reigned forty years total', 'Twenty-five years old; he reigned thirty years total', 'Thirty-five years old; he reigned thirty years', 'Twenty years old; he reigned fifty years', 'a', '2 Samuel 5:4 — "David was thirty years old when he began to reign, and he reigned forty years."'),
('2 Samuel', 5, 'teens', 3, 'What mocking challenge did the Jebusites make when David attacked Jerusalem?', 'That even the blind and the lame could hold the city against him', 'That David''s army was too small to breach the walls', 'That their gods were more powerful than the LORD', 'That they would destroy all of Israel if David attacked', 'a', '2 Samuel 5:6 — "The Jebusites said to David, Except thou take away the blind and the lame, thou shalt not come in hither."'),
('2 Samuel', 5, 'teens', 4, 'In what direction from which location did the Philistines spread out when they heard David had been made king?', 'They spread in the valley of Rephaim', 'They marched up from Ashkelon along the coast', 'They gathered in the plain of Jezreel', 'They camped in the valley of Elah', 'a', '2 Samuel 5:18 — "The Philistines also came and spread themselves in the valley of Rephaim."'),
('2 Samuel', 5, 'teens', 5, 'What divine strategy did God give David for the second battle against the Philistines?', 'To come upon them from behind opposite the mulberry trees and wait for the sound of marching in the treetops', 'To send the ark of the covenant before the army', 'To attack at dawn before the Philistines had eaten', 'To divide the army into three units and attack from three sides', 'a', '2 Samuel 5:23-24 — "Thou shalt not go up; but fetch a compass behind them, and come upon them over against the mulberry trees. And...when thou hearest the sound of a going in the tops of the mulberry trees, that then thou shalt bestir thyself."'),
-- Adults
('2 Samuel', 5, 'adults', 1, 'What was the length of David''s reign in Hebron over Judah and his reign in Jerusalem over all Israel?', 'Seven years and six months in Hebron; thirty-three years in Jerusalem', 'Ten years in Hebron; thirty years in Jerusalem', 'Five years in Hebron; thirty-five years in Jerusalem', 'Three years in Hebron; thirty-seven years in Jerusalem', 'a', '2 Samuel 5:5 — "In Hebron he reigned over Judah seven years and six months: and in Jerusalem he reigned thirty and three years over all Israel and Judah."'),
('2 Samuel', 5, 'adults', 2, 'What method of capturing Jerusalem did Joab apparently use, earning him the position of chief captain?', 'He went up via the water shaft (gutter) to attack the Jebusites', 'He breached the north wall at night', 'He tunneled under the city gate', 'He scaled the walls with ladders during a feast', 'a', '2 Samuel 5:8 — "Whosoever getteth up to the gutter, and smiteth the Jebusites..." — this is parallel to 1 Chronicles 11:6 where Joab went first and became chief.'),
('2 Samuel', 5, 'adults', 3, 'What divine declaration confirmed David''s kingship over Israel in his own understanding?', 'He knew the LORD had established him king over Israel, and that He had exalted his kingdom for His people Israel''s sake', 'A vision of fire confirmed David''s throne would endure forever', 'The prophet Nathan declared a blessing over Jerusalem at the coronation', 'The Urim and Thummim confirmed David''s right to the throne', 'a', '2 Samuel 5:12 — "David perceived that the LORD had established him king over Israel, and that he had exalted his kingdom for his people Israel''s sake."'),
('2 Samuel', 5, 'adults', 4, 'What does the name "Baal-perazim" mean and why did David name the site this?', 'The LORD that breaketh through; because God broke through David''s enemies like a flood', 'The place of victory; because David had won his greatest battle there', 'The house of the LORD; because David prayed there before the battle', 'The plain of the sword; because many Philistines died there', 'a', '2 Samuel 5:20 — "David called the name of that place Baal-perazim. For the LORD had broken forth upon mine enemies before me, as the breach of waters."'),
('2 Samuel', 5, 'adults', 5, 'What did David do with the Philistine idols abandoned on the battlefield at Baal-perazim?', 'He and his men carried them away and burned them', 'He melted them down for the treasury', 'He set them up as a memorial of victory', 'He sent them to Hebron for the priests to destroy', 'a', '2 Samuel 5:21 — "And there they left their images, and David and his men burned them." (cf. 1 Chronicles 14:12)'),
('2 Samuel', 5, 'adults', 6, 'How does God''s instruction to "wait for the sound of a going in the tops of the mulberry trees" demonstrate the uniqueness of the second Philistine battle strategy?', 'God gave a supernatural sign before commanding the attack, indicating divine timing and angelic intervention', 'David was told to use stealth rather than direct assault for the first time', 'The mulberry trees marked the boundary of sacred territory', 'The strategy was borrowed from Philistine military doctrine', 'a', '2 Samuel 5:24 — "When thou hearest the sound of a going in the tops of the mulberry trees, that then thou shalt bestir thyself: for then shall the LORD go out before thee."'),
('2 Samuel', 5, 'adults', 7, 'What does the account of David taking more concubines and wives in Jerusalem reveal about the political culture of the ancient Near East?', 'The expansion of a royal harem signified international prestige and political alliances, though it conflicted with Deuteronomy 17:17', 'It shows David was following the custom God had approved for Israelite kings', 'It was required to produce enough heirs to secure the dynasty', 'It demonstrated David''s personal reward for faithful service to God', 'a', '2 Samuel 5:13 — "David took him more concubines and wives out of Jerusalem, after he was come from Hebron." This practice violated Deuteronomy 17:17 and contributed to later family strife.'),
('2 Samuel', 5, 'adults', 8, 'What key phrase in 2 Samuel 5:10 summarizes the theological interpretation of David''s growing power?', 'The LORD God of hosts was with him', 'God had anointed him with an everlasting anointing', 'The Spirit of the LORD rested upon him continually', 'The hand of the LORD was strong upon him from his youth', 'a', '2 Samuel 5:10 — "David went on, and grew great, and the LORD God of hosts was with him."');

-- ═══ 2 Samuel Chapter 6 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Samuel', 6, 'kids', 1, 'What special box did David try to bring to Jerusalem?', 'The ark of God', 'The tabernacle of Moses', 'The golden lampstand', 'The bronze altar', 'a', '2 Samuel 6:2 — "David arose...to bring up from thence the ark of God, whose name is called by the name of the LORD of hosts that dwelleth between the cherubims."'),
('2 Samuel', 6, 'kids', 2, 'What happened to Uzzah when he touched the ark?', 'God struck him dead', 'He was struck blind', 'He fell asleep immediately', 'He was healed of a sickness', 'a', '2 Samuel 6:7 — "The anger of the LORD was kindled against Uzzah; and God smote him there for his error; and there he died by the ark of God."'),
('2 Samuel', 6, 'kids', 3, 'How did David celebrate when the ark was finally brought into Jerusalem?', 'He danced before the LORD with all his might', 'He built a bonfire and sang praises all night', 'He sat quietly and prayed for hours', 'He led a great march around the city walls', 'a', '2 Samuel 6:14 — "David danced before the LORD with all his might."'),
-- Teens
('2 Samuel', 6, 'teens', 1, 'Why did David leave the ark at the house of Obed-edom for three months instead of bringing it to Jerusalem?', 'Because he was afraid of the LORD after Uzzah was struck dead', 'Because the cart that carried it broke down', 'Because the priests needed time to prepare the city', 'Because Michal refused to let it enter the city', 'a', '2 Samuel 6:9 — "David was afraid of the LORD that day, and said, How shall the ark of the LORD come to me?"'),
('2 Samuel', 6, 'teens', 2, 'What encouraged David to finally bring the ark to Jerusalem after leaving it with Obed-edom?', 'The LORD had blessed the house of Obed-edom because of the ark', 'A prophet told him it was safe to proceed', 'The three months of mourning for Uzzah were complete', 'Obed-edom asked David to take it away', 'a', '2 Samuel 6:12 — "It was told king David, saying, The LORD hath blessed the house of Obed-edom, and all that pertaineth unto him, because of the ark of God."'),
('2 Samuel', 6, 'teens', 3, 'What did David sacrifice when the ark had been carried just six steps?', 'An ox and a fatling', 'Seven lambs and a bull', 'Two turtledoves and a young pigeon', 'A burnt offering and a peace offering', 'a', '2 Samuel 6:13 — "When they that bare the ark of the LORD had gone six paces, he sacrificed oxen and fatlings."'),
('2 Samuel', 6, 'teens', 4, 'Who despised David for dancing and leaping before the ark?', 'Michal the daughter of Saul', 'Joab the son of Zeruiah', 'The elders of Israel', 'The priests of the tabernacle', 'a', '2 Samuel 6:16 — "Michal Saul''s daughter looked through a window, and saw king David leaping and dancing before the LORD; and she despised him in her heart."'),
('2 Samuel', 6, 'teens', 5, 'What blessing and gift did David give to all the people of Israel at the end of the celebration?', 'A loaf of bread, a piece of flesh, and a flagon of wine', 'Silver and gold from the royal treasury', 'A garment and a blessing in the LORD''s name', 'Land and an inheritance in Jerusalem', 'a', '2 Samuel 6:19 — "He dealt among all the people, even among the whole multitude of Israel, as well to the women as men, to every one a cake of bread, and a good piece of flesh, and a flagon of wine."'),
-- Adults
('2 Samuel', 6, 'adults', 1, 'From where was the ark being brought, and what was the significance of that location?', 'From Baale of Judah (Kirjath-jearim), where it had rested since the Philistines returned it after their plague', 'From the tabernacle at Shiloh where Samuel had served', 'From Nob where the priests had kept it during Saul''s reign', 'From the house of Abinadab in Gibeah after the battle of Ebenezer', 'a', '2 Samuel 6:2 — "David arose...and went...to bring up from thence the ark of God." The ark had been in the house of Abinadab at the hill of Kirjath-jearim since 1 Samuel 7:1.'),
('2 Samuel', 6, 'adults', 2, 'What was Uzzah''s error that caused his death, according to the text?', 'He put forth his hand and took hold of the ark when the oxen shook it', 'He carried the ark on a new cart against the prescribed method', 'He looked inside the ark when the cover shifted', 'He spoke words of disrespect toward the ark during the journey', 'a', '2 Samuel 6:6 — "Uzzah put forth his hand to the ark of God, and took hold of it; for the oxen shook it." This violated Numbers 4:15 which forbade touching the holy things.'),
('2 Samuel', 6, 'adults', 3, 'What specific clothing was David wearing as he danced before the LORD?', 'A linen ephod', 'His royal robes', 'Sackcloth and ashes', 'A white priestly garment', 'a', '2 Samuel 6:14 — "David was clothed with a robe of fine linen, and all the Levites that bare the ark, and the singers...David also had upon him an ephod of linen."'),
('2 Samuel', 6, 'adults', 4, 'What was the content of Michal''s rebuke of David when he returned to bless his household?', 'She accused him of uncovering himself vainly in the eyes of the handmaids of his servants', 'She told him a king should not behave like a common man', 'She said he had shamed the royal household before all Israel', 'She rebuked him for spending treasury money on festivities', 'a', '2 Samuel 6:20 — "Michal the daughter of Saul came out to meet David, and said, How glorious was the king of Israel to day, who uncovered himself to day in the eyes of the handmaids of his servants."'),
('2 Samuel', 6, 'adults', 5, 'What was David''s theological defense of his dancing before the LORD against Michal''s contempt?', 'He declared it was before the LORD who chose him over Saul, and he would be even more vile and base in his own sight', 'He told her that kings in all nations dance before their gods', 'He reminded her that the priests themselves danced during sacrifices', 'He said a vision had commanded him to dance as an act of worship', 'a', '2 Samuel 6:21-22 — "It was before the LORD, which chose me before thy father, and before all his house...and I will yet be more vile than thus, and will be base in mine own sight."'),
('2 Samuel', 6, 'adults', 6, 'What consequence did Michal suffer for despising David''s worship?', 'She had no child unto the day of her death', 'She was divorced from David and sent back to her father''s house', 'She was stripped of her royal honors', 'She was confined to her chambers for the rest of her life', 'a', '2 Samuel 6:23 — "Therefore Michal the daughter of Saul had no child unto the day of her death."'),
('2 Samuel', 6, 'adults', 7, 'What does the text reveal about the previous handling of the ark that made the use of a cart theologically problematic?', 'The Law prescribed Kohathite Levites to carry the ark on their shoulders with poles, never on a cart', 'The ark had always been kept stationary in the tabernacle and never moved', 'A new cart had been used by the Philistines as an act of disrespect', 'Only the high priest was permitted to supervise the ark''s transport', 'a', '2 Samuel 6:3 — "They set the ark of God upon a new cart." This violated Numbers 7:9 and 4:15, which required the Kohathites to carry it on their shoulders. The Philistines'' cart method (1 Sam 6) was not the model to follow.'),
('2 Samuel', 6, 'adults', 8, 'Where did David place the ark after bringing it to Jerusalem, and what offerings did he make?', 'In a tent he had prepared; he offered burnt offerings and peace offerings', 'In the existing tabernacle at Gibeon', 'In the royal palace until the temple could be built', 'On a threshing floor on Mount Moriah', 'a', '2 Samuel 6:17 — "They brought in the ark of the LORD, and set it in his place, in the midst of the tabernacle that David had pitched for it: and David offered burnt offerings and peace offerings before the LORD."');

-- ═══ 2 Samuel Chapter 7 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Samuel', 7, 'kids', 1, 'What did David want to build for God?', 'A temple, a house of cedar', 'A great altar on a mountain', 'A city with walls and towers', 'A garden with an ark in the center', 'a', '2 Samuel 7:2 — "David said unto Nathan the prophet, See now, I dwell in an house of cedar, but the ark of God dwelleth within curtains."'),
('2 Samuel', 7, 'kids', 2, 'Who told David that he would NOT be the one to build God''s house?', 'Nathan the prophet', 'The high priest Abiathar', 'The angel of the LORD', 'God speaking in a dream', 'a', '2 Samuel 7:13 — God told Nathan to tell David that his son would build the house — "He shall build an house for my name, and I will stablish the throne of his kingdom for ever."'),
('2 Samuel', 7, 'kids', 3, 'What did God promise to do for David''s family forever?', 'Establish his throne forever', 'Give his family great riches', 'Make his children strong warriors', 'Give Israel the largest kingdom on earth', 'a', '2 Samuel 7:16 — "Thine house and thy kingdom shall be established for ever before thee: thy throne shall be established for ever."'),
-- Teens
('2 Samuel', 7, 'teens', 1, 'What was Nathan''s initial response when David told him he wanted to build a house for God?', 'He said, Go, do all that is in thine heart, for the LORD is with thee', 'He said David must wait and pray for God''s guidance first', 'He said the LORD had not commanded a temple to be built', 'He said only a priest could receive God''s instructions for a temple', 'a', '2 Samuel 7:3 — "Nathan said to the king, Go, do all that is in thine heart; for the LORD is with thee."'),
('2 Samuel', 7, 'teens', 2, 'In the Davidic covenant, what does God promise to be toward David''s son if he commits iniquity?', 'A father who chastens with the rod of men but will not take His mercy away', 'A judge who will remove the kingdom from him', 'A righteous God who will pardon all his sins', 'A king who will fight his enemies for him', 'a', '2 Samuel 7:14-15 — "I will be his father, and he shall be my son. If he commit iniquity, I will chasten him with the rod of men...But my mercy shall not depart away from him."'),
('2 Samuel', 7, 'teens', 3, 'What did God say He had done for David since taking him from the sheepfold?', 'He had been with him, cut off his enemies, made him a great name, and appointed a place for Israel', 'He had protected him from all harm and given him wisdom', 'He had sent angels to guard his steps and defeat his foes', 'He had revealed His law to him alone and made him a prophet', 'a', '2 Samuel 7:8-9 — "I took thee from the sheepcote, from following the sheep...I was with thee whithersoever thou wentest, and have cut off all thine enemies...and have made thee a great name."'),
('2 Samuel', 7, 'teens', 4, 'What question did David ask to express his humility before God in his prayer of thanksgiving?', 'Who am I, O Lord GOD, and what is my house, that thou hast brought me hitherto?', 'What have I done to deserve such great mercies, O LORD?', 'How can I repay thee for all the blessings thou hast given me?', 'Shall thy servant be worthy to receive such an everlasting promise?', 'a', '2 Samuel 7:18 — "Then went king David in, and sat before the LORD, and he said, Who am I, O Lord GOD? and what is my house, that thou hast brought me hitherto?"'),
('2 Samuel', 7, 'teens', 5, 'What is the Davidic covenant''s significance for Messianic prophecy in the New Testament?', 'It points forward to Jesus Christ as the eternal heir of David''s throne whose kingdom has no end', 'It was fulfilled entirely by Solomon''s temple construction', 'It applies only to the physical descendants of David up to the exile', 'It was superseded by the new covenant at Sinai', 'a', '2 Samuel 7:16 — "Thine house and thy kingdom shall be established for ever" — fulfilled in Luke 1:32-33 where the angel says of Jesus, "The Lord God shall give unto him the throne of his father David: And he shall reign over the house of Jacob for ever."'),
-- Adults
('2 Samuel', 7, 'adults', 1, 'What specific rhetorical question did God ask about Israel''s history to argue against the need for a permanent temple?', 'Whether He had ever commanded any tribe of Israel to build Him a house of cedar', 'Whether Solomon had yet been born to build the temple', 'Whether the tabernacle at Shiloh had not been sufficient worship', 'Whether the ark had rested long enough in its current location', 'a', '2 Samuel 7:7 — "In all the places wherein I have walked with all the children of Israel spake I a word with any of the tribes of Israel, whom I commanded to feed my people Israel, saying, Why build ye not me an house of cedar?"'),
('2 Samuel', 7, 'adults', 2, 'What specific name-building promise does God make to David that parallels the Tower of Babel narrative in reverse?', 'God will make David a great name, as opposed to men attempting to make a great name for themselves at Babel', 'God promises to give David the same fame as Abraham', 'God says David''s name will be greater than all the kings of the earth', 'God promises that David''s name will be written in the heavens', 'a', '2 Samuel 7:9 — "I...have made thee a great name, like unto the name of the great men that are in the earth." Compare Genesis 11:4 where men sought to "make us a name" — God grants what He chooses to grant.'),
('2 Samuel', 7, 'adults', 3, 'What does the Hebrew play on words between "house" (bayit) in this chapter illuminate about God''s response to David?', 'David wanted to build God a house (temple) but God says He will build David a house (dynasty)', 'The word house means both dwelling place and family line in Hebrew', 'David''s house of cedar pointed to the eternal dwelling of God', 'The house of Israel is the only house God truly inhabits', 'a', '2 Samuel 7:11 — "The LORD telleth thee that he will make thee an house." The wordplay: David plans to build a bayit (temple) for God; God will build a bayit (dynasty) for David.'),
('2 Samuel', 7, 'adults', 4, 'What phrase in the covenant did God NOT say about any previous leader of Israel, making the Davidic covenant unique?', 'I will be his father and he shall be my son', 'I will cut off thine enemies from before thee', 'I will give thee rest from all thine enemies', 'I will appoint a place for my people Israel', 'a', '2 Samuel 7:14 — "I will be his father, and he shall be my son" — this father-son language was not applied to Moses, Joshua, or Saul, making it uniquely covenantal and ultimately Messianic.'),
('2 Samuel', 7, 'adults', 5, 'In David''s prayer, what theological declaration does he make about the uniqueness of God compared to all other gods?', 'There is none like God; there is no God beside Him according to all that Israel had heard', 'God alone has created the heavens and earth and all that exists', 'God is higher than all princes and kings of the nations', 'God''s name alone shall be worshipped in all the earth', 'a', '2 Samuel 7:22 — "Wherefore thou art great, O LORD God: for there is none like thee, neither is there any God beside thee, according to all that we have heard with our ears."'),
('2 Samuel', 7, 'adults', 6, 'What intercessory element does David include in his prayer that goes beyond personal gratitude?', 'He asks God to confirm the promise and bless the house of David forever that Israel may be established', 'He asks God to forgive all his past sins before establishing the covenant', 'He intercedes for the sins of his children in advance', 'He asks that the nations of the earth would know of God''s greatness', 'a', '2 Samuel 7:25-26 — "And now, O LORD God, the word that thou hast spoken concerning thy servant...let it be established for ever...And let thy name be magnified for ever."'),
('2 Samuel', 7, 'adults', 7, 'What does David mean by declaring "with thy blessing let the house of thy servant be blessed for ever"?', 'He acknowledges that only God''s ongoing blessing can sustain the covenant, not David''s merit or might', 'He is asking for material prosperity for his descendants', 'He is requesting that God swear the covenant by an oath', 'He is claiming the covenant as an unconditional right', 'a', '2 Samuel 7:29 — "Therefore now let it please thee to bless the house of thy servant, that it may continue for ever before thee: for thou, O Lord GOD, hast spoken it: and with thy blessing let the house of thy servant be blessed for ever."'),
('2 Samuel', 7, 'adults', 8, 'How does the phrase "for thy word''s sake" in David''s prayer reflect the basis of the covenant?', 'David grounds his confidence entirely in God''s spoken word and revealed character, not in human achievement', 'David is quoting a previous prophecy from Samuel', 'David is referencing the written law of Moses', 'David is appealing to God''s covenant with Abraham as the basis', 'a', '2 Samuel 7:21 — "For thy word''s sake, and according to thine own heart, hast thou done all these great things." David recognizes the covenant rests on God''s word and will, not David''s worthiness.');

-- ═══ 2 Samuel Chapter 8 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Samuel', 8, 'kids', 1, 'What people did David defeat first in the battles described in chapter 8?', 'The Philistines', 'The Ammonites', 'The Assyrians', 'The Egyptians', 'a', '2 Samuel 8:1 — "David smote the Philistines, and subdued them: and David took Metheg-ammah out of the hand of the Philistines."'),
('2 Samuel', 8, 'kids', 2, 'What did David do with the gold shields he captured from the servants of Hadadezer?', 'He brought them to Jerusalem', 'He melted them down for the temple', 'He gave them to the priests', 'He sent them back as a peace offering', 'a', '2 Samuel 8:7 — "David took the shields of gold that were on the servants of Hadadezer, and brought them to Jerusalem."'),
('2 Samuel', 8, 'kids', 3, 'What did David dedicate to God from all the silver, gold, and bronze he captured from the nations?', 'He dedicated them unto the LORD', 'He gave them to the soldiers who fought', 'He kept them in the royal treasury', 'He used them to build his palace', 'a', '2 Samuel 8:11 — "Which also king David did dedicate unto the LORD, with the silver and gold that he had dedicated of all nations which he subdued."'),
-- Teens
('2 Samuel', 8, 'teens', 1, 'What did David do to the Moabites he defeated, and what was their tribute obligation?', 'He made them lie down in lines, measuring with a cord, killing two lines and sparing one; they became servants paying tribute', 'He enslaved all of them and set them to work on the city walls', 'He expelled them from their land and gave it to the tribe of Reuben', 'He killed only the soldiers and let the civilians return home freely', 'a', '2 Samuel 8:2 — "He smote Moab, and measured them with a line, casting them down to the ground; even with two lines measured he to put to death, and with one full line to keep alive. And so the Moabites became David''s servants, and brought gifts."'),
('2 Samuel', 8, 'teens', 2, 'Who was Hadadezer, and where was he from?', 'He was the son of Rehob, king of Zobah in Syria', 'He was the king of Damascus and a vassal of Assyria', 'He was the Philistine general who led the army at the valley of Rephaim', 'He was an Ammonite prince who allied with the Moabites', 'a', '2 Samuel 8:3 — "David smote also Hadadezer, the son of Rehob, king of Zobah."'),
('2 Samuel', 8, 'teens', 3, 'What did David do to the chariot horses of Hadadezer?', 'He houghed (hamstrung) all but one hundred horses he reserved for chariots', 'He captured them all and added them to his royal stables', 'He sent them to Solomon in Egypt as trade', 'He sacrificed them as burnt offerings to the LORD', 'a', '2 Samuel 8:4 — "David houghed all the chariot horses, but reserved of them for an hundred chariots."'),
('2 Samuel', 8, 'teens', 4, 'What was the name of David''s priest and scribe mentioned among his chief officers?', 'Zadok and Seraiah (Sheva)', 'Abiathar and Ahimelech', 'Eleazar and Phinehas', 'Benaiah and Hushai', 'a', '2 Samuel 8:17 — "Zadok the son of Ahitub, and Ahimelech the son of Abiathar, were the priests; and Seraiah was the scribe."'),
('2 Samuel', 8, 'teens', 5, 'What phrase is repeatedly used in chapter 8 to explain David''s military success?', 'The LORD preserved David whithersoever he went', 'The Spirit of the LORD went before him into battle', 'God gave David victory over all his foes', 'The arm of the LORD was mighty for Israel', 'a', '2 Samuel 8:6, 14 — "The LORD preserved David whithersoever he went" (appears twice, in verses 6 and 14).'),
-- Adults
('2 Samuel', 8, 'adults', 1, 'What was "Metheg-ammah" that David took from the Philistines?', 'The bridle of the mother city, meaning Gath and its dependent towns', 'The Philistine treasury at Ashdod', 'The military stronghold at the border of Ekron', 'A title of sovereignty over the Philistine coastal plain', 'a', '2 Samuel 8:1 — "David took Metheg-ammah out of the hand of the Philistines." The Hebrew means "bridle of the mother city," understood as control of Gath (cf. 1 Chronicles 18:1).'),
('2 Samuel', 8, 'adults', 2, 'What was the significant quantity of Syrians David killed at the valley of salt?', 'He slew eighteen thousand Syrians of Damascus who came to succour Hadadezer', 'He killed two thousand horsemen and ten thousand foot soldiers', 'He smote twenty thousand from across the Euphrates', 'He put thirty thousand to flight and captured five thousand', 'a', '2 Samuel 8:5 — "The Syrians of Damascus came to succour Hadadezer king of Zobah, David slew of the Syrians two and twenty thousand men."'),
('2 Samuel', 8, 'adults', 3, 'What does Toi king of Hamath''s greeting of David reveal about the geopolitical situation of the ancient Near East?', 'He sent his son Joram with gifts of silver, gold, and brass because David had defeated his enemy Hadadezer', 'He sent tribute out of fear that David would invade his territory next', 'He sought a military alliance against the Philistines', 'He was seeking a marriage alliance with the house of David', 'a', '2 Samuel 8:9-10 — "Toi king of Hamath heard that David had smitten all the host of Hadadezer...Toi sent Joram his son unto king David, to salute him...for Hadadezer had wars with Toi."'),
('2 Samuel', 8, 'adults', 4, 'What was the name of David''s chief military officer over the army?', 'Joab the son of Zeruiah', 'Benaiah the son of Jehoiada', 'Abishai the son of Zeruiah', 'Ittai the Gittite', 'a', '2 Samuel 8:16 — "Joab the son of Zeruiah was over the host."'),
('2 Samuel', 8, 'adults', 5, 'What role did Benaiah the son of Jehoiada hold in David''s administration?', 'He was over both the Cherethites and the Pelethites (the royal bodyguard)', 'He was the recorder and kept the royal chronicles', 'He was over the tribute and taxes of the conquered nations', 'He was David''s personal armor-bearer and shield-carrier', 'a', '2 Samuel 8:18 — "Benaiah the son of Jehoiada was over both the Cherethites and the Pelethites."'),
('2 Samuel', 8, 'adults', 6, 'What was the role of Jehoshaphat the son of Ahilud?', 'He was the recorder', 'He was the chief scribe of the king', 'He was the captain of the host', 'He was the treasurer over the dedicated things', 'a', '2 Samuel 8:16 — "Jehoshaphat the son of Ahilud was recorder."'),
('2 Samuel', 8, 'adults', 7, 'What does the statement "David executed judgment and justice unto all his people" reveal about the nature of Davidic kingship?', 'It shows the king''s role as supreme judge was inseparable from his military and administrative functions', 'It means David personally tried every legal case in Israel', 'It indicates that David was primarily a lawgiver rather than a warrior', 'It describes only his judicial role, separate from his priestly functions', 'a', '2 Samuel 8:15 — "David reigned over all Israel; and David executed judgment and justice unto all his people." This reflects the ideal of the covenant king as shepherd-judge.'),
('2 Samuel', 8, 'adults', 8, 'What was the destination of the silver and gold from David''s dedicated spoils, and what purpose was it saved for?', 'It was brought to Jerusalem and later used by Solomon for the construction of the temple', 'It was distributed among the Levites for the upkeep of the tabernacle', 'It was stored in the treasury to pay David''s soldiers', 'It was used to build the walls and gates of the city of David', 'a', '2 Samuel 8:11 — "Which also king David did dedicate unto the LORD." 1 Kings 7:51 and 1 Chronicles 18:11 confirm these treasures were eventually used in Solomon''s temple.');

-- ═══ 2 Samuel Chapter 9 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Samuel', 9, 'kids', 1, 'Whose family did David want to show kindness to because of a promise he had made?', 'Jonathan''s family', 'Saul''s servants'' families', 'The family of Abner', 'The family of Jesse his father', 'a', '2 Samuel 9:1 — "David said, Is there yet any that is left of the house of Saul, that I may shew him kindness for Jonathan''s sake?"'),
('2 Samuel', 9, 'kids', 2, 'What was the name of Jonathan''s son whom David helped?', 'Mephibosheth', 'Ishvi', 'Armoni', 'Abinadab', 'a', '2 Samuel 9:6 — "Now when Mephibosheth, the son of Jonathan, the son of Saul, was come unto David, he fell on his face, and did reverence."'),
('2 Samuel', 9, 'kids', 3, 'What disability did Mephibosheth have?', 'He was lame in both his feet', 'He was blind in one eye', 'He was deaf and could not speak', 'He had lost an arm in battle', 'a', '2 Samuel 9:13 — "Mephibosheth dwelt in Jerusalem: for he did eat continually at the king''s table; and was lame on both his feet."'),
-- Teens
('2 Samuel', 9, 'teens', 1, 'Who was Ziba, and how did he help David find Mephibosheth?', 'He was a servant of Saul''s house who told David that Jonathan''s son Mephibosheth was in Lo-debar', 'He was a Benjaminite soldier who had served Ish-bosheth', 'He was the steward of David''s palace who had known Jonathan personally', 'He was a scout sent by Joab to search the land of Benjamin', 'a', '2 Samuel 9:2-4 — "There was of the house of Saul a servant whose name was Ziba...And the king said, Is there not yet any of the house of Saul...? And Ziba said...Jonathan hath yet a son, which is lame on his feet...in Lo-debar."'),
('2 Samuel', 9, 'teens', 2, 'What was the name of the man in whose house Mephibosheth was living?', 'Machir the son of Ammiel', 'Barzillai the Gileadite', 'Shobi the son of Nahash', 'Kimham the son of Barzillai', 'a', '2 Samuel 9:4-5 — "He is in the house of Machir, the son of Ammiel, in Lo-debar...Then king David sent, and fetched him out of the house of Machir, the son of Ammiel, from Lo-debar."'),
('2 Samuel', 9, 'teens', 3, 'What did David give back to Mephibosheth from Saul''s estate?', 'All the land that belonged to Saul and all his father''s house', 'A palace in Jerusalem and a bodyguard', 'Saul''s crown and weapons', 'The throne of Benjamin and its tribute', 'a', '2 Samuel 9:9 — "The king called to Ziba, Saul''s servant, and said unto him, I have given unto thy master''s son all that pertained to Saul and to all his house."'),
('2 Samuel', 9, 'teens', 4, 'Who was appointed to farm Saul''s land on behalf of Mephibosheth?', 'Ziba and his fifteen sons and twenty servants', 'Ittai the Gittite and his band', 'The sons of Rechab who had served Ish-bosheth', 'Benaiah and the Cherethites and Pelethites', 'a', '2 Samuel 9:10 — "Thou therefore, and thy sons, and thy servants, shall till the land for him...So Ziba had fifteen sons and twenty servants."'),
('2 Samuel', 9, 'teens', 5, 'What great privilege did David grant Mephibosheth as a sign of royal favor?', 'He would eat at David''s table as one of the king''s sons', 'He would receive a monthly stipend from the royal treasury', 'He would be given a place of honor at all state ceremonies', 'He would be exempt from all taxes and military service', 'a', '2 Samuel 9:11 — "Mephibosheth shall eat at my table, as one of the king''s sons."'),
-- Adults
('2 Samuel', 9, 'adults', 1, 'What specific covenant with Jonathan is being fulfilled in David''s actions in chapter 9?', 'The covenant of 1 Samuel 20:15-17 where Jonathan asked David to show kindness to his house and not cut off his kindness from his house forever', 'The covenant made at Mizpah when the tribes renewed their allegiance', 'A private oath David swore at the death of Jonathan in the lament of chapter 1', 'The covenant written in the book of Jasher regarding the house of Saul', 'a', '2 Samuel 9:1 — "Is there yet any that is left of the house of Saul, that I may shew him kindness for Jonathan''s sake?" — This fulfills 1 Samuel 20:15: "Thou shalt not cut off thy kindness from my house for ever."'),
('2 Samuel', 9, 'adults', 2, 'What does Mephibosheth''s self-deprecating response reveal about his self-image and his understanding of royal grace?', 'He called himself a dead dog, showing he had no expectation of kindness and understood David''s act as pure grace', 'He expressed confidence that David would honor his lineage', 'He reminded David of his father Jonathan''s loyal service', 'He asked only for a small gift and permission to return to Lo-debar', 'a', '2 Samuel 9:8 — "What is thy servant, that thou shouldest look upon such a dead dog as I am?" — Mephibosheth saw himself as worthless, making David''s restoration of him a picture of sovereign grace.'),
('2 Samuel', 9, 'adults', 3, 'What does the place name "Lo-debar" mean, and how does it heighten the narrative?', 'Lo-debar means "no pasture" or "nothing," emphasizing Mephibosheth''s state of deprivation before David found him', 'Lo-debar means "the place of hiding," indicating Mephibosheth was in danger', 'Lo-debar means "city of the lame," because disabled people were exiled there', 'Lo-debar means "beyond the river," referring to its location east of the Jordan', 'a', '2 Samuel 9:4 — Mephibosheth was in Lo-debar. The Hebrew lo-debar means "no pasture/no word/nothing," creating a literary contrast with the abundance of David''s table to which Mephibosheth is invited.'),
('2 Samuel', 9, 'adults', 4, 'What specific instruction did David give Ziba regarding productivity from Saul''s land?', 'Thou shalt till the land for him, and thou shalt bring in the fruits, that thy master''s son may have food to eat', 'Ziba was to give half the produce to the king and half to Mephibosheth', 'Ziba was to manage the estate but report all income to David''s treasurer', 'Ziba was to restore the land to its original boundaries before dividing it', 'a', '2 Samuel 9:10 — "Thou therefore, and thy sons, and thy servants, shall till the land for him, and thou shalt bring in the fruits, that thy master''s son may have food to eat."'),
('2 Samuel', 9, 'adults', 5, 'How many sons and servants did Ziba have working on Saul''s land?', 'Fifteen sons and twenty servants', 'Ten sons and thirty servants', 'Five sons and forty servants', 'Twenty sons and fifteen servants', 'a', '2 Samuel 9:10 — "Now Ziba had fifteen sons and twenty servants."'),
('2 Samuel', 9, 'adults', 6, 'What theological theme does chapter 9 illustrate that New Testament writers would later apply to salvation?', 'God''s unmerited covenant love (hesed) to the helpless — Mephibosheth pictures the sinner brought to the king''s table not by merit but by covenant', 'The principle that faithfulness in small things leads to greater responsibility', 'The obligation of rulers to care for the physical needs of their subjects', 'The importance of keeping national unity through acts of generosity', 'a', '2 Samuel 9:7 — "I will surely shew thee kindness for Jonathan thy father''s sake." The Hebrew word hesed (steadfast covenant love) describes an act of grace toward one who had no claim or merit.'),
('2 Samuel', 9, 'adults', 7, 'Where specifically did Mephibosheth reside after being restored, and what does this signify politically?', 'He dwelt in Jerusalem, eating continually at the king''s table, kept under David''s watchful eye', 'He returned to Lo-debar to manage Saul''s estate from there', 'He was given a house in Gibeah, the city of Saul''s ancestral territory', 'He lived in Hebron among the elders of Judah for protection', 'a', '2 Samuel 9:13 — "So Mephibosheth dwelt in Jerusalem: for he did eat continually at the king''s table." Keeping potential rival claimants close and fed was both politically prudent and personally generous.'),
('2 Samuel', 9, 'adults', 8, 'How does the narrative of Mephibosheth function as a literary chiasm with 2 Samuel 4:4?', 'Both passages identify Mephibosheth as lame; chapter 4 places him in obscurity while chapter 9 brings him to the king''s table, framing the intervening political chaos with covenant-faithfulness bookends', 'Both passages describe acts of violence against Saul''s family and their consequences', 'Both passages use the same Hebrew term for royal mercy applied to different characters', 'Both passages are connected by the covenant made at Mizpah in Samuel''s time', 'a', '2 Samuel 4:4 introduces Mephibosheth amid the political violence of dynastic succession; 2 Samuel 9 resolves his story with covenant restoration — the editorial placement frames David''s reign with hesed rather than conquest.');

-- ═══ 2 Samuel Chapter 10 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Samuel', 10, 'kids', 1, 'Why did David send messengers to the Ammonites?', 'To show kindness because their king Nahash had died', 'To demand tribute after defeating them', 'To invite them to a feast in Jerusalem', 'To warn them against attacking Israel', 'a', '2 Samuel 10:2 — "Then said David, I will shew kindness unto Hanun the son of Nahash, as his father shewed kindness unto me."'),
('2 Samuel', 10, 'kids', 2, 'What did the Ammonite king Hanun do to David''s servants to insult them?', 'He shaved off half their beards and cut off their garments to their buttocks', 'He threw them in prison for three days', 'He sent them back with a threatening letter', 'He made them bow before the Ammonite idols', 'a', '2 Samuel 10:4 — "Hanun took David''s servants, and shaved off the one half of their beards, and cut off their garments in the middle, even to their buttocks."'),
('2 Samuel', 10, 'kids', 3, 'Who won the great battle between Israel and the Ammonites and their hired allies?', 'Israel and David''s army', 'The Syrians hired by the Ammonites', 'The Ammonites with their many soldiers', 'The Ammonites and the army of Hadadezer', 'a', '2 Samuel 10:18 — "David slew the men of seven hundred chariots of the Syrians, and forty thousand horsemen."'),
-- Teens
('2 Samuel', 10, 'teens', 1, 'What false accusation did the Ammonite princes make about David''s real purpose in sending the messengers?', 'That David had sent them to search and spy out the city in order to destroy it', 'That David wanted to marry Hanun''s sister as a political alliance', 'That David intended to demand the throne of Ammon as tribute', 'That David was looking for an excuse to break the old treaty', 'a', '2 Samuel 10:3 — "The princes of the children of Ammon said unto Hanun their lord, Thinkest thou that David doth honour thy father...hath not David rather sent his servants unto thee, to search the city, and to spy it out, and to overthrow it?"'),
('2 Samuel', 10, 'teens', 2, 'What did David tell his shamed servants to do while they waited for their beards to grow back?', 'Tarry at Jericho until their beards be grown, then return', 'Return to Hebron and remain there in hiding', 'Stay in the wilderness of Judah until the shame had passed', 'Go to their own cities and rest until David sent for them', 'a', '2 Samuel 10:5 — "Tarry at Jericho until your beards be grown, and then return."'),
('2 Samuel', 10, 'teens', 3, 'What nations did the Ammonites hire to fight against Israel?', 'Syrians of Beth-rehob, Zobah, the king of Maacah, and the men of Tob', 'Philistines of Gaza and Ashkelon', 'Edomites and Moabites', 'Men of Hamath and soldiers from Damascus', 'a', '2 Samuel 10:6 — "The children of Ammon sent and hired the Syrians of Beth-rehob, and the Syrians of Zoba, twenty thousand footmen, and of king Maacah a thousand men, and of Ish-tob twelve thousand men."'),
('2 Samuel', 10, 'teens', 4, 'How did Joab divide his forces to fight a battle on two fronts simultaneously?', 'He faced the Syrians with his best troops and gave the rest to Abishai to face the Ammonites', 'He sent the cavalry against the Ammonites and the infantry against the Syrians', 'He placed the ark of the covenant between the two battle lines', 'He positioned David''s mighty men at the center and the regular army on the wings', 'a', '2 Samuel 10:9-10 — "Joab saw that the front of the battle was against him before and behind...he chose of all the choice men of Israel, and put them in array against the Syrians: And the rest of the people he delivered into the hand of Abishai his brother."'),
('2 Samuel', 10, 'teens', 5, 'What happened when the Syrians saw they were being beaten and who regrouped them for a second battle?', 'They fled; Hadadezer sent for the Syrians beyond the river and Shobach his captain gathered them', 'They made peace with David and returned home voluntarily', 'They were all captured and brought to Jerusalem as prisoners', 'Hadadezer himself led a second charge that was repelled by Joab', 'a', '2 Samuel 10:15-16 — "When the Syrians saw that they were smitten before Israel, they gathered themselves together...and Hadarezer sent, and brought out the Syrians that were beyond the river: and they came to Helam; and Shobach the captain of the host of Hadarezer went before them."'),
-- Adults
('2 Samuel', 10, 'adults', 1, 'What prior act of kindness had Nahash king of Ammon shown to David, motivating his diplomatic mission to Hanun?', 'Nahash had shown kindness to David, though the precise act is not specified in Samuel but may relate to shelter during David''s exile from Saul', 'Nahash had sent military aid to David during the siege of Ziklag', 'Nahash had provided food and supplies during David''s years in Adullam', 'Nahash had released Israelite prisoners held during Saul''s reign', 'a', '2 Samuel 10:2 — "As his father shewed kindness unto me." The nature of Nahash''s kindness to David is not explained in this passage; it may connect to 1 Samuel 22 when David sought refuge during his fugitive years.'),
('2 Samuel', 10, 'adults', 2, 'What does the phrase "sat still" (or "abode in their cities") by the Ammonites after the first Syrian rout reveal?', 'After the Syrians fled, the Ammonites withdrew into their city, ending the first engagement before a full Israelite assault on Rabbah', 'The Ammonites were preparing a second ambush for Joab''s forces', 'The Ammonites were negotiating a separate peace with Abishai', 'The Ammonites had run out of hired soldiers and were regrouping', 'a', '2 Samuel 10:14 — "When the children of Ammon saw that the Syrians were fled, then fled they also before Abishai, and entered into the city. So Joab returned from the children of Ammon, and came to Jerusalem."'),
('2 Samuel', 10, 'adults', 3, 'What was the location of the decisive second battle between David and the Syrians?', 'Helam', 'Gibeon', 'Medeba', 'Aroer', 'a', '2 Samuel 10:17 — "When it was told David, he gathered all Israel together, and passed over Jordan, and came to Helam. And the Syrians set themselves in array against David, and fought with him."'),
('2 Samuel', 10, 'adults', 4, 'What were the casualty figures David inflicted on the Syrians in the second battle?', 'He slew seven hundred chariot men and forty thousand horsemen and killed Shobach the captain', 'He killed ten thousand horsemen and captured the Syrian king', 'He destroyed three hundred chariots and slew twenty thousand foot soldiers', 'He put fifty thousand to flight and took the Syrian camp', 'a', '2 Samuel 10:18 — "David slew the men of seven hundred chariots of the Syrians, and forty thousand horsemen, and smote Shobach the captain of their host, who died there."'),
('2 Samuel', 10, 'adults', 5, 'What was the political consequence for the vassal kings of Hadadezer after their defeat?', 'They made peace with Israel and served them; they were afraid to help the Ammonites any more', 'They were absorbed into the kingdom of Israel as tribute-paying provinces', 'They fled beyond the Euphrates and were never heard from again', 'They surrendered their territory to Joab and withdrew to Assyria', 'a', '2 Samuel 10:19 — "And when all the kings that were servants to Hadarezer saw that they were smitten before Israel, they made peace with Israel, and served them."'),
('2 Samuel', 10, 'adults', 6, 'What does Joab''s exhortation to Abishai before battle reveal about Israelite military theology?', 'He declared they would fight for their people and the cities of God and let the LORD do what seemed good to Him', 'He told Abishai that numbers did not matter because the LORD would give victory', 'He reminded Abishai of David''s past victories as proof God would fight for them', 'He said their covenant with God guaranteed them victory if they were faithful', 'a', '2 Samuel 10:12 — "Be of good courage, and let us play the men for our people, and for the cities of our God: and the LORD do that which seemeth him good."'),
('2 Samuel', 10, 'adults', 7, 'What does the diplomatic incident in chapter 10 reveal about the dangers of misread intentions in international relations?', 'Hanun''s advisors misinterpreted a genuine act of hesed as espionage, turning a potential alliance into a costly war through paranoia and counsel of distrust', 'It shows that Ammonite intelligence was superior to Israel''s diplomatic code', 'It reveals that David''s empire was so threatening that even friendly overtures were suspected', 'It demonstrates that ancient Near Eastern diplomacy required military escorts for all embassies', 'a', '2 Samuel 10:3-4 — The princes'' bad advice ("thinkest thou that David doth honour thy father?") led to needless war, showing how false counsel and distrust can destroy peace.'),
('2 Samuel', 10, 'adults', 8, 'How does chapter 10 function as a narrative transition toward the Bathsheba episode in chapter 11?', 'It establishes the ongoing siege of Rabbah as the military context into which the Bathsheba narrative is inserted — "at the time when kings go forth to battle" David stays in Jerusalem', 'It introduces Uriah the Hittite as a military hero before his death in chapter 11', 'It shows David becoming complacent about his military duties as his empire expanded', 'It demonstrates that David''s enemies were all defeated before his greatest moral failure', 'a', '2 Samuel 10:14 — "Joab returned from the children of Ammon, and came to Jerusalem." 2 Samuel 11:1 opens: "And it came to pass...at the time when kings go forth to battle...David tarried still at Jerusalem" — the unfinished Ammonite war provides the backdrop for David''s fall.');
